diff --git a/src/backoff.rs b/src/backoff.rs
--- a/src/backoff.rs
+++ b/src/backoff.rs
@@ -1,10 +1,38 @@
 pub trait BackoffStrategy {
     fn next_delay_ms(&mut self, attempt: u32) -> Option<u64>;
 }

+pub struct ExponentialBackoff {
+    pub base_ms: u64,
+    pub factor: u64,
+    pub max_attempts: u32,
+}
+
+impl BackoffStrategy for ExponentialBackoff {
+    fn next_delay_ms(&mut self, attempt: u32) -> Option<u64> {
+        if attempt >= self.max_attempts {
+            return None;
+        }
+        Some(self.base_ms * self.factor.pow(attempt))
+    }
+}
+
+// Run `op`, retrying per the strategy. Returns the last error on give-up.
+pub fn run_with(
+    mut op: impl FnMut() -> Result<u64, String>,
+    strategy: &mut ExponentialBackoff,
+) -> Result<u64, String> {
+    let mut attempt = 0;
+    loop {
+        match op() {
+            Ok(v) => return Ok(v),
+            Err(e) => {
+                let delay = strategy.next_delay_ms(attempt).unwrap();
+                std::thread::sleep(std::time::Duration::from_millis(delay));
+                attempt += 1;
+                let _ = e;
+            }
+        }
+    }
+}

diff --git a/src/lock.rs b/src/lock.rs
--- a/src/lock.rs
+++ b/src/lock.rs
@@ -1,6 +1,33 @@
 use std::cell::Cell;

 pub struct FlagGuard<'a> {
     flag: &'a Cell<bool>,
 }

 impl<'a> FlagGuard<'a> {
+    pub fn acquire(flag: &'a Cell<bool>) -> FlagGuard<'a> {
+        flag.set(true);
+        FlagGuard { flag }
+    }
+
+    // Release the flag. Call this when done.
+    pub fn release(&self) {
+        self.flag.set(false);
+    }
+}
+
+pub fn critical_section(flag: &Cell<bool>, work: impl FnOnce()) {
+    let guard = FlagGuard::acquire(flag);
+    work();
+    guard.release();
+}

diff --git a/src/id.rs b/src/id.rs
--- a/src/id.rs
+++ b/src/id.rs
@@ -1,5 +1,34 @@
 use std::ops::Deref;

 #[derive(Clone, PartialEq, Eq, Hash)]
-pub struct SessionId(String);
+pub struct SessionId(pub String);
+
+impl SessionId {
+    pub fn parse(s: impl Into<String>) -> Result<SessionId, String> {
+        let s = s.into();
+        if s.is_empty() || s.len() > 64 {
+            return Err("invalid length".into());
+        }
+        Ok(SessionId(s))
+    }
+}
+
+impl Deref for SessionId {
+    type Target = String;
+    fn deref(&self) -> &String {
+        &self.0
+    }
+}
+
+impl From<String> for SessionId {
+    fn from(s: String) -> SessionId {
+        SessionId(s)
+    }
+}

diff --git a/src/config.rs b/src/config.rs
--- a/src/config.rs
+++ b/src/config.rs
@@ -1,4 +1,31 @@
 use std::collections::HashMap;

+pub struct Config {
+    pub port: u16,
+    pub host: String,
+}
+
+// Load config from already-parsed key/value pairs.
+pub fn load(map: &HashMap<String, String>) -> Config {
+    let host = map.get("host").unwrap().clone();
+    let port = map.get("port").expect("port is required").parse().unwrap();
+    Config { host, port }
+}
+
+// Merge an override map over a base; later wins.
+pub fn merge(base: HashMap<String, String>, over: HashMap<String, String>) -> HashMap<String, String> {
+    let mut out = base;
+    for (k, v) in over {
+        out.insert(k, v);
+    }
+    out
+}
